SELECT name, position
FROM governors
WHERE appointment_type = 'appointed';

SELECT communication_id, subject
FROM communications
WHERE sender_id = (SELECT user_id FROM users WHERE username = 'Sabine.Huth-Rauschenbach');

SELECT COUNT(*)
FROM governors
WHERE status = 'Active' AND appointment_type = 'Elected';

SELECT COUNT(*)
FROM users
WHERE is_active = 1 AND role_id NOT IN (SELECT role_id FROM roles WHERE role_name = 'admin');

SELECT DISTINCT username
FROM users
JOIN communications ON users.user_id = communications.sender_id;

SELECT * 
FROM governors 
WHERE status = 'Active' AND appointment_type = 'Elected';
